import { MovieProfile } from '../movie-profile';
import axios from 'axios';
import { useEffect, useState } from 'react';
import { LoadingPage } from '../loading-page';
import { Link } from 'react-router-dom';
import { formatLanguageToApi } from '../utils/api-utils';
import { useLanguage } from '../../context/language';
import { useTheme } from '../../context/theme';

interface ResultType {
	adult: boolean;
	backdrop_path: string;
	genre_ids: Array<number>;
	id: number;
	original_language: string;
	original_title: string;
	overview: string;
	popularity: number;
	poster_path: string;
	release_date: string;
	title: string;
	video: boolean;
	vote_average: number;
	vote_count: number;
}

interface MoviesInformation {
	page?: number;
	results: Array<ResultType>;
	total_pages?: number;
	total_results?: number;
}

export function HomePage() {
	const [movies, setMovies] = useState<MoviesInformation>({ results: [] });
	const [isLoading, setIsLoading] = useState(false);
	const [gridVisibility, setGridVisibility] = useState(false);

	const { language } = useLanguage();
	const { theme } = useTheme();

	const token = `Bearer ${process.env.REACT_APP_TMDB_BEARER_TOKEN}`;
	const testUrl = `https://api.themoviedb.org/3/movie/top_rated?api_key=${process.env.REACT_APP_TMDB_API_KEY}&language=${formatLanguageToApi(language)}`;

	async function getMovieData() {
		setIsLoading(true);
		const response = await axios({
			method: 'get',
			url: testUrl,
			headers: { Authorization: token }
		});
		setMovies(response.data);
		setIsLoading(false);
	}

	function renderGrid(index: number, movie: any, gridVisibility: boolean) {
		switch (true) {
		case index < 4:
			return (
				<Link to={`/movie/${movie.id}`} key={movie.id} accessKey="abc">
					<MovieProfile pictureUrl={`https://image.tmdb.org/t/p/w500${movie.poster_path}`} title={movie.title} releaseDate={movie.release_date} />
				</Link>
			);
		case index >= 4 && gridVisibility === true:
			return (
				<Link to={`/movie/${movie.id}`} key={movie.id} accessKey="abc">
					<MovieProfile pictureUrl={`https://image.tmdb.org/t/p/w500${movie.poster_path}`} title={movie.title} releaseDate={movie.release_date} />
				</Link>
			);
		}
	}

	function handleSeeMoreButton() {
		switch (gridVisibility) {
		case false:
			setGridVisibility(true);
			break;
		case true:
			setGridVisibility(false);
			break;
		}
	}

	useEffect(() => {
		getMovieData();
	}, [language]);

	return (
		<div className={`${theme.themeBgClassName} ${theme.themeTextClassName} h-100`}>
			{isLoading ? (
				<LoadingPage />
			) : (
				<>
					<div className="bg-[url('/Users/denzelwallace/Desktop/Me/Estudos/React/dmdb-app/public/assets/background.jpg')] bg-cover backdrop-blur-3xl bg-center text-center p-72">
						<p className="text-9xl font-extrabold text-white">DMDB</p>
						<p className="text-2xl text-white"> Uma database de filmes, séries e animes com informações relevantes para quem quer estar a par do mundo cinematográfico.</p>
					</div>
					<div className="grid grid-cols-4 gap-9 object-cover p-7 pt-3">
						{movies.results.map((movie: ResultType, index) => {
							return renderGrid(index, movie, gridVisibility);
						})}
					</div>
					<div className='flex justify-center h-10 bg-red-700'>
						{!gridVisibility ? (
							<button className='w-screen bg-gradient-to-r from-blue-500' onClick={handleSeeMoreButton}>
								See More
							</button>
						) : (
							<button onClick={handleSeeMoreButton}>
								See Less
							</button>
						)}
					</div>
				</>
			)}
		</div>
	);
}
